```class Solution {
    public int palindromePartition(String s, int k) {
        int n = s.length();
        int[] dp = new int[n];
        for (int i = 0; i < n; i++) {
            int j = i;
            while (j >= 0 && i + 1 <= n - 1 && s.charAt(j) == s.charAt(i + 1)) {
                j--;
                i++;
            }
            dp[i] = i - j - 1;
        }
        int res = dp[0];
        for (int i = 1; i < n; i++) {
            res = Math.max(res, dp[i]);
        }
        return res;
    }
}```
